// Outputs: [downloadedFiles[], errorMsg]
if (flow.get('poll_inflight') === true) {
    return null;
}
flow.set('poll_inflight', true);

const host = env.get('SFTP_HOST');
const port = Number(env.get('SFTP_PORT') || 22);
const username = env.get('SFTP_USERNAME');
const password = env.get('SFTP_PASSWORD');
const keyFile = env.get('SFTP_KEY_FILENAME');
const knownHostsFile = env.get('SFTP_KNOWN_HOSTS_FILE');
const allowUnknown = env.get('SFTP_ALLOW_UNKNOWN_HOSTS') === 'true';
const remotePath = env.get('SFTP_REMOTE_PATH') || '/ingest';
const archivePath = env.get('SFTP_ARCHIVE_PATH') || '/archive';
const accepted = (env.get('INGEST_ACCEPTED_EXTENSIONS') || '.json,.csv,.avro')
    .split(',').map(s => s.trim().toLowerCase());
const maxSize = Number(env.get('INGEST_MAX_FILE_SIZE_BYTES') || 104857600);

if (!host || !username) {
    flow.set('poll_inflight', false);
    node.error('SFTP_HOST and SFTP_USERNAME must be set on the ORCE pod env');
    return null;
}
if (!keyFile && !password) {
    flow.set('poll_inflight', false);
    node.error('SFTP_PASSWORD or SFTP_KEY_FILENAME must be set');
    return null;
}
if (!knownHostsFile && !allowUnknown) {
    flow.set('poll_inflight', false);
    node.error('Refusing connect: SFTP_KNOWN_HOSTS_FILE not set and SFTP_ALLOW_UNKNOWN_HOSTS != true (paramiko RejectPolicy parity)');
    return null;
}

const t0 = Date.now();
const client = new SftpClient();
const connectOpts = {
    host: host,
    port: port,
    username: username,
    readyTimeout: 20000
};
if (keyFile) {
    try { connectOpts.privateKey = nodeFs.readFileSync(keyFile); }
    catch (e) {
        flow.set('poll_inflight', false);
        node.error('Cannot read SFTP_KEY_FILENAME=' + keyFile + ': ' + e.message);
        return null;
    }
} else {
    connectOpts.password = password;
}
if (knownHostsFile) {
    try {
        const known = nodeFs.readFileSync(knownHostsFile, 'utf8');
        const fingerprints = [];
        for (const line of known.split(/\r?\n/)) {
            const m = line.trim().match(/^[^\s]+\s+ssh-(?:rsa|ed25519|dss)\s+([A-Za-z0-9+/=]+)/);
            if (m) {
                const sha = nodeCrypto.createHash('sha256').update(Buffer.from(m[1], 'base64')).digest('hex');
                fingerprints.push(sha);
            }
        }
        connectOpts.hostVerifier = (hashHex) => fingerprints.includes(hashHex);
    } catch (e) {
        flow.set('poll_inflight', false);
        node.error('Cannot read known_hosts ' + knownHostsFile + ': ' + e.message);
        return null;
    }
}

async function ensureArchive() {
    try { await client.stat(archivePath); }
    catch (_) { try { await client.mkdir(archivePath, true); } catch (_) {} }
}

async function archiveOne(remoteFile, archiveFile) {
    try {
        await client.rename(remoteFile, archiveFile);
        return null;
    } catch (e) {
        // Mirror sftp_poller.py:177-180 — retry with timestamp suffix
        const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
        try {
            await client.rename(remoteFile, archiveFile + '.' + ts);
            return null;
        } catch (e2) {
            return e2;
        }
    }
}

(async () => {
    const downloaded = [];
    const dlqEvents = [];
    try {
        await client.connect(connectOpts);
        await ensureArchive();
        const entries = await client.list(remotePath);
        const ingestTs = new Date().toISOString();
        const archiveOps = [];

        for (const e of entries) {
            if (e.type !== '-') continue;
            const name = e.name;
            const dotIdx = name.lastIndexOf('.');
            const ext = dotIdx >= 0 ? name.slice(dotIdx).toLowerCase() : '';
            if (!accepted.includes(ext)) continue;
            if (e.size > maxSize) continue;
            const remoteFile = remotePath.replace(/\/$/, '') + '/' + name;
            const archiveFile = archivePath.replace(/\/$/, '') + '/' + name;
            try {
                const buf = await client.get(remoteFile);
                downloaded.push({
                    filename: name,
                    remote_file: remoteFile,
                    archive_file: archiveFile,
                    size_bytes: e.size,
                    ext: ext,
                    is_regular: true,
                    content: buf,
                    source_topic: 'sftp://' + host + remoteFile,
                    ingest_timestamp: ingestTs,
                    tick_id: msg.tick_id
                });
                archiveOps.push({ remoteFile, archiveFile });
            } catch (e2) {
                dlqEvents.push({
                    error_type: 'sftp',
                    error_message: 'download ' + name + ': ' + e2.message,
                    error_timestamp: new Date().toISOString(),
                    filename: name,
                    source_topic: 'sftp://' + host + remoteFile
                });
            }
        }

        // Emit downloaded files first so parsers can run while we archive.
        if (downloaded.length > 0) {
            node.send([downloaded, null]);
        }

        // Archive after emitting (mirrors Python single-session model).
        for (const op of archiveOps) {
            const err = await archiveOne(op.remoteFile, op.archiveFile);
            if (err) {
                dlqEvents.push({
                    error_type: 'archive',
                    error_message: err.message,
                    error_timestamp: new Date().toISOString(),
                    filename: op.remoteFile.split('/').pop(),
                    source_topic: 'sftp://' + host + op.remoteFile
                });
            }
        }
    } catch (err) {
        const m = global.get('metrics') || {};
        m.facis_sftp_poll_errors_total = (m.facis_sftp_poll_errors_total || 0) + 1;
        global.set('metrics', m);
        dlqEvents.push({
            error_type: 'sftp',
            error_message: 'cycle: ' + err.message,
            error_timestamp: new Date().toISOString(),
            filename: null,
            source_topic: 'sftp://' + host + remotePath
        });
    } finally {
        try { await client.end(); } catch (_) {}
        const m2 = global.get('metrics') || {};
        m2.facis_sftp_poll_duration_seconds = m2.facis_sftp_poll_duration_seconds || { buckets: {}, sum: 0, count: 0 };
        const elapsed = (Date.now() - t0) / 1000;
        m2.facis_sftp_poll_duration_seconds.sum += elapsed;
        m2.facis_sftp_poll_duration_seconds.count += 1;
        for (const b of [0.1, 0.5, 1, 5, 10, 30, 60]) {
            if (elapsed <= b) m2.facis_sftp_poll_duration_seconds.buckets[b] =
                (m2.facis_sftp_poll_duration_seconds.buckets[b] || 0) + 1;
        }
        global.set('metrics', m2);
        flow.set('last_poll_ms', Date.now());
        flow.set('poll_inflight', false);

        for (const dlq of dlqEvents) {
            node.send([null, { payload: dlq, filename: dlq.filename }]);
        }
    }
})();

return null;
